let left_button = document.getElementById("yt-left-button"); let right_button = document.getElementById("yt-right-button"); let yt_carousel = document.getElementById("yt_carousel_items"); let playerScreen = document.getElementById("yt-shorts-play"); let playNext = document.getElementById("yt-bg-cover-right"); let playPrev = document.getElementById("yt-bg-cover-left"); let closeShort = document.getElementById("yt-bg-cover-close") let width = (yt_carousel.clientWidth)/2; var currentElement = false; var current_short_iframe = false; left_button.addEventListener("click", ()=>{ let width = yt_carousel.clientWidth; yt_carousel.scrollLeft -= width; }) right_button.addEventListener("click", () => { yt_carousel.scrollLeft += width; }) playNext.addEventListener("click", ()=>{ playNextShort(); }) playPrev.addEventListener("click", ()=>{ playPreviousShort(); }) closeShort.addEventListener("click", ()=> { close_short_screen(); }) let shortsArray = document.getElementsByClassName("yt-carousal-item"); for(let i = 0; i < shortsArray.length; i++) { let element = shortsArray[i]; element.addEventListener("click",function() { load_short(this); }) }; function load_short(element){ console.log("Triggered Load short"); let shortId = element.getAttribute("yt_id"); currentElement = element; console.log("currentElement=>", currentElement); let iframe = generateIframe(shortId); current_short_iframe = iframe; console.log("current_short_iframe =>", current_short_iframe); playerScreen.insertBefore(iframe, playerScreen.firstChild); display_short_screen(); } function generateIframe(shortId){ let iframe = document.createElement("iframe"); iframe.src = "https://www.youtube.com/embed/" + shortId + "?autoplay=1"; iframe.frameBorder = 0; iframe.allow = "autoplay; encrypted-media"; iframe.style.width = "auto"; iframe.style.height = "100%"; return iframe; } function display_short_screen(){ playerScreen.style.display = "block"; return; } function removeCurrentShortIframe(){ if(current_short_iframe){ current_short_iframe.remove(); } console.log("removeCurrentShortIframe=>", current_short_iframe); return; } function close_short_screen(){ console.log("command to close screen") playerScreen.style.display = "none"; removeCurrentShortIframe(); return; } function playNextShort(){ if(currentElement){ let nextElement = currentElement.nextElementSibling; if(nextElement){ playPrev.style.display = "block"; currentElement = nextElement; let shortId = currentElement.getAttribute("yt_id"); let iframe = generateIframe(shortId); removeCurrentShortIframe(); playerScreen.insertBefore(iframe, playerScreen.firstChild); current_short_iframe = iframe; }else{ playNext.style.display = "none"; } } return; } function playPreviousShort(){ if(currentElement){ let previousElement = currentElement.previousElementSibling; console.log("previousElement =>", previousElement); if(previousElement){ playNext.style.display = "block"; currentElement = previousElement; let shortId = currentElement.getAttribute("yt_id"); let iframe = generateIframe(shortId); removeCurrentShortIframe(); playerScreen.insertBefore(iframe, playerScreen.firstChild); current_short_iframe = iframe; }else{ playPrev.style.display = "none"; } } return; }

